import React, { useCallback, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  detectDateRangePreset,
  SearchTextInput,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  LinListTableConfigModal,
  loadErpListTableConfig,
  saveErpListTableConfig,
  useViewMobileLayout,
    useErpListSelection,
  useServerPagedListLoading,
  ListGridBusyWrap,
  LabelMoney,
  type ErpListTableConfig,
  formatUTCToLocalDisplay,
} from '@linm-soft-org/linm-web-common-components';
import { useVoucherInitData } from '../../hooks/useVoucherInitData';
import { useAppDispatch } from '../../store/hooks';
import { bhService } from '../../services/bh/bhService';
import type { InvoiceDto } from '../../services/bh/models';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
} from '../../utils/voucherListRowMenuHint';
import {
  formatProcessingLevelFromOptions,
  resolveProcessingLevelSelectOptions,
} from '../../utils/voucherProcessingLevelOptions';
import { canEditFromListRow, canViewLedgerFromListRow } from '../../utils/voucherListRowActions';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { LIST_FILTER_SCOPE } from '../../constants/listFilterScopes';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../voucher-list/VoucherRowActionMenu';
import { VoucherListSelectionBanner } from '../voucher-list/VoucherListSelectionBanner';
import { resolveVoucherBatchIds } from '../../utils/resolveVoucherBatchIds';
import { ProcessingLevelApproveModal } from '../voucher/ProcessingLevelApproveModal';
import { VoucherPostedLedgerModal } from '../voucher/VoucherPostedLedgerModal';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import { VoucherListTableSkeleton } from '../list/VoucherListTableSkeleton';
import erp from '../../styles/erpPage.module.css';

const TEST_ID = 'bh-hoa-don';
const PAGE_ID = 'bh-hoa-don';
const CREATE_FORM = 'create-sales-invoice';

const LIST_COLUMNS = [
  { id: 'code', label: 'Số HĐ' },
  { id: 'invoiceDate', label: 'Ngày' },
  { id: 'customerName', label: 'Khách hàng' },
  { id: 'totalAmount', label: 'Tổng tiền' },
  { id: 'processingLevel', label: 'Mức xử lý' },
] as const;

function isRowSelectable(row: InvoiceDto): boolean {
  return row.status === 'Draft';
}

export const HoaDonList: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const {
    initialized,
    fromDate,
    toDate,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    processingLevel,
    setProcessingLevel,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(LIST_FILTER_SCOPE.hoaDonBan);
  const [items, setItems] = useState<InvoiceDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(DEFAULT_PAGE_SIZE);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(TEST_ID),
  );
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: InvoiceDto } | null>(null);

  const { processingLevelOptions, defaultProcessingLevel } = useVoucherInitData(CREATE_FORM);
  const {
    canCreate,
    canApprove,
    canUpdate,
    canViewLedger: canViewLedgerPerm,
  } = useVoucherListActions(CREATE_FORM);

  const levelOptions = useMemo(
    () => resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel),
    [processingLevelOptions, defaultProcessingLevel],
  );

  const processingLevelFilterOptions = useMemo(
    () => [{ value: '', label: 'Tất cả mức xử lý' }, ...levelOptions],
    [levelOptions],
  );

  const formatProcessingLabel = (level: string | undefined) =>
    formatProcessingLevelFromOptions(level, processingLevelOptions);

  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const visibleColumns = LIST_COLUMNS;

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable,
  });

  const pageSelectableCount = useMemo(
    () => items.filter(isRowSelectable).length,
    [items],
  );

  const fetchInvoicePage = useCallback(
    async (p: number, ps: number) => {
      const res = await bhService.getInvoices({
        fromDate,
        toDate,
        search: search || undefined,
        processingLevel: processingLevel || undefined,
        page: p,
        pageSize: ps,
      });
      return { items: res.items, totalCount: res.totalCount };
    },
    [fromDate, toDate, search, processingLevel],
  );

  const activeRow = selection.activeRow;
  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow ? canEditFromListRow(activeRow, canUpdate) : false;
  const canViewLedgerActive = activeRow
    ? canViewLedgerFromListRow(activeRow, canViewLedgerPerm)
    : false;

  const refresh = useCallback(() => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection, setLoadingMode]);

  const handleSearch = () => {
    pulseSearch(() => {
      setLoadingMode('filter');
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };

  const setPageSize = (size: number) => {
    setLoadingMode('filter');
    setPageSizeState(size as ListPageSize);
    setPage(1);
    selection.clearSelection();
  };

  const navigateToRow = useCallback(
    (id: string, startInEditMode?: boolean) => {
      navigate(`/bh/hoa-don/${id}`, {
        state: startInEditMode ? { startInEditMode: true } : undefined,
      });
    },
    [navigate],
  );

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      fetchInvoicePage(page, pageSize)
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, 'Lỗi tải danh sách hóa đơn'),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) endFetch();
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [initialized, page, pageSize, reloadKey, dispatch, beginFetch, endFetch, fetchInvoicePage]);

  const handleBatchApproveConfirm = useCallback(async (newLevel: string) => {
    setApproving(true);
    try {
      const ids = await resolveVoucherBatchIds(
        selection,
        items,
        isRowSelectable,
        fetchInvoicePage,
        totalCount,
      );
      if (ids.length === 0) {
        dispatchAppToast(dispatch, {
          message: 'Không có hóa đơn Nháp hợp lệ để phê duyệt',
          type: 'warning',
        });
        return;
      }
      await bhService.batchUpdateInvoiceProcessingLevel({ ids, processingLevel: newLevel });
      dispatchAppToast(dispatch, { message: 'Phê duyệt thành công', type: 'success' });
      setShowApproveModal(false);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Phê duyệt thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  }, [selection, items, fetchInvoicePage, totalCount, dispatch]);

  const handleSaveTableConfig = (config: ErpListTableConfig) => {
    setTableConfig(config);
    saveErpListTableConfig(TEST_ID, config);
    setShowConfigModal(false);
  };

  const rowMenuHintMessage = viewMobile
    ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
    : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: InvoiceDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') navigateToRow(row.id);
      if (action === 'edit' && canEditFromListRow(row, canUpdate)) {
        navigateToRow(row.id, true);
      }
      if (action === 'viewLedger' && canViewLedgerFromListRow(row, canViewLedgerPerm)) {
        setShowLedgerModal(true);
      }
    },
    [rowMenu?.row, canUpdate, canViewLedgerPerm, navigateToRow],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = rowMenuRow ? canEditFromListRow(rowMenuRow, canUpdate) : false;
  const rowMenuViewLedgerDisabled = rowMenuRow
    ? !canViewLedgerFromListRow(rowMenuRow, canViewLedgerPerm)
    : true;

  const renderCell = (row: InvoiceDto, colId: string) => {
    switch (colId) {
      case 'code':
        return (
          <button
            type="button"
            className={erp.codeLink}
            onClick={() => navigateToRow(row.id)}
            data-testid={`${TEST_ID}-row-${row.id}-code`}
          >
            <code>{row.code}</code>
          </button>
        );
      case 'invoiceDate':
        return formatUTCToLocalDisplay(row.invoiceDate, false);
      case 'customerName':
        return row.customerName;
            case 'totalAmount':
        return <span className={erp.colRight}><LabelMoney layout="value" variant="cell" value={row.totalAmount} /></span>;
      case 'processingLevel':
        return (
          <span data-testid={`${TEST_ID}-row-${row.id}-processing-level`}>
            {formatProcessingLabel(row.processingLevel)}
          </span>
        );
      default:
        return null;
    }
  };

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canApprove,
      approveDisabled: selection.selectedCount === 0,
      onApprove: () => setShowApproveModal(true),
      canViewLedger: canViewLedgerActive,
      onViewLedger: () => setShowLedgerModal(true),
      canPrint: false,
      canView: canViewActive,
      onView: () => activeRow && navigateToRow(activeRow.id),
      canEdit: canEditActive,
      onEdit: () => activeRow && navigateToRow(activeRow.id, true),
      canCreate,
      onCreate: () => navigate('/bh/hoa-don/them'),
      onEditConfig: () => setShowConfigModal(true),
    }),
    [
      canApprove,
      selection.selectedCount,
      canViewLedgerActive,
      canViewActive,
      canEditActive,
      canCreate,
      activeRow,
      refresh,
      navigate,
      navigateToRow,
    ],
  );

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setLoadingMode('filter');
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm số HĐ, số CT cũ (FM), khách hàng, số HĐĐT..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-processingLevel`}>
              <Select
                label="Mức xử lý"
                value={processingLevel}
                onChange={e => {
                  setLoadingMode('filter');
                  setProcessingLevel(e.target.value);
                  resetPage();
                }}
                options={processingLevelFilterOptions}
                data-testid={`${TEST_ID}-processing-level`}
              />
            </div>
          </>
        )}
      />
    ),
    [
      searchDraft,
      fromDate,
      toDate,
      processingLevel,
      processingLevelFilterOptions,
      applyDateRange,
      resetPage,
      setSearchDraft,
      setProcessingLevel,
      handleSearch,
      setLoadingMode,
      showTableLoading,
    ],
  );

  const selectionBanner = (
    <VoucherListSelectionBanner
      testIdPrefix={TEST_ID}
      selectedCount={selection.selectedCount}
      totalCount={totalCount}
      selectionMode={selection.selectionMode}
      pageSelectableCount={pageSelectableCount}
      onSelectAllDatabase={selection.selectAllInDatabase}
      onClear={selection.clearSelection}
    />
  );

  const listBody =
    showTableLoading ? (
      <VoucherListTableSkeleton rows={Math.min(pageSize, 8)} testIdPrefix={TEST_ID} />
    ) : items.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <p>Không có hóa đơn</p>
      </div>
    ) : (
      <ListGridBusyWrap pageLoading={pageLoading}>
        <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table-wrapper`}>
          <table className={erp.table} data-testid={`${TEST_ID}-table`}>
            <thead>
              <tr>
                <th className={erp.colCheck}>
                  <input
                    type="checkbox"
                    checked={selection.isPageAllSelected}
                    onChange={selection.togglePageAll}
                    aria-label="Chọn tất cả trên trang"
                    data-testid={`${TEST_ID}-select-all-page`}
                  />
                </th>
                {visibleColumns.map(col => (
                  <th key={col.id}>{col.label}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {items.map(row => {
                const isActive = selection.isRowActive(row);
                const isChecked = selection.isRowChecked(row);
                return (
                  <tr
                    key={row.id}
                    className={[
                      isChecked ? erp.catalogRowChecked : '',
                      isActive ? erp.catalogRowActive : '',
                    ]
                      .filter(Boolean)
                      .join(' ')}
                    onClick={() => selection.selectActiveRow(row)}
                    onContextMenu={e => {
                      e.preventDefault();
                      handleRowOpenActionMenu({ row, x: e.clientX, y: e.clientY });
                    }}
                    data-testid={`${TEST_ID}-row-${row.id}`}
                  >
                    <td className={erp.colCheck}>
                      {row.status === 'Draft' ? (
                        <input
                          type="checkbox"
                          checked={isChecked}
                          onChange={() => selection.toggleRow(row, !isChecked)}
                          onClick={e => e.stopPropagation()}
                          data-testid={`${TEST_ID}-row-${row.id}-check`}
                        />
                      ) : null}
                    </td>
                    {visibleColumns.map(col => (
                      <td key={col.id}>{renderCell(row, col.id)}</td>
                    ))}
                  </tr>
                );
              })}
            </tbody>
          </table>
          <p className={erp.rowMenuHint} data-testid={`${TEST_ID}-row-menu-hint`}>
            {rowMenuHintMessage}
          </p>
        </div>
      </ListGridBusyWrap>
    );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: 'Hóa đơn bán',
          titleIconClass: 'fas fa-file-invoice',
          pageId: PAGE_ID,
        }}
        voucherToolbar={voucherToolbar}
        beforeToolbar={selectionBanner}
        listTitle="Danh sách hóa đơn"
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={false}
        footer={
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => {
              setLoadingMode('page');
              setPage(p);
              selection.clearSelection();
            }}
            onPageSizeChange={setPageSize}
          />
        }
        modals={
          <>
            <LinListTableConfigModal
              isOpen={showConfigModal}
              onClose={() => setShowConfigModal(false)}
              testIdPrefix={TEST_ID}
              config={tableConfig}
              onSave={handleSaveTableConfig}
            />
            <ProcessingLevelApproveModal
              isOpen={showApproveModal}
              onClose={() => setShowApproveModal(false)}
              currentLevel={String(defaultProcessingLevel ?? levelOptions[0]?.value ?? '')}
              levelOptions={levelOptions}
              onConfirm={handleBatchApproveConfirm}
              saving={approving}
              testIdPrefix={TEST_ID}
            />
            {activeRow && showLedgerModal ? (
              <VoucherPostedLedgerModal
                isOpen={showLedgerModal}
                onClose={() => setShowLedgerModal(false)}
                voucherTitle={`Hóa đơn ${activeRow.code}`}
                testIdPrefix={TEST_ID}
                fetchPostedLedger={() => bhService.getInvoicePostedLedger(activeRow.id)}
                fetchPostingStatus={async () => {
                  const ps = await bhService.getInvoicePostingStatus(activeRow.id);
                  return { postingStatus: ps.postingStatus, lastError: ps.lastError };
                }}
              />
            ) : null}
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView
              showEdit={rowMenuShowEdit}
              showViewLedger={!rowMenuViewLedgerDisabled}
              showPrint={false}
            />
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default HoaDonList;
